INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_watermark$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "A line on the wall. Mineral-white, ruler-straight, deposited by water that rose to this exact height and held there long enough to leave a record. The line is old. The precision is not. Something measured this room before you entered it.", "text_de": "Eine Linie an der Wand. Mineralweiß, linealgrade, hinterlassen von Wasser, das bis zu genau dieser Höhe stieg und lang genug dort verharrte, um eine Aufzeichnung zu hinterlassen. Die Linie ist alt. Die Präzision nicht. Etwas hat diesen Raum vermessen, bevor ihr ihn betreten habt."}, "echo": {"text_en": "{agent} finds another watermark. Higher. Same mineral deposit, same precision. The water has been here before – more than once. Each visit, it stayed longer.", "text_de": "{agent} findet ein weiteres Wasserzeichen. Höher. Selbe Mineralablagerung, selbe Präzision. Das Wasser war schon hier – mehr als einmal. Bei jedem Besuch blieb es länger."}, "mutation": {"text_en": "The wall is a chronicle. Dozens of lines, each higher than the last, each a record of a flood that rose and receded and rose again. The intervals between them are shrinking. The most recent line is still damp.", "text_de": "Die Wand ist eine Chronik. Dutzende Linien, jede höher als die vorige, jede eine Aufzeichnung einer Flut, die stieg und wich und wieder stieg. Die Abstände zwischen ihnen werden kleiner. Die jüngste Linie ist noch feucht."}, "climax": {"text_en": "One line remains. At the ceiling. The mineral deposit is fresh – still crystallizing. The water that made this mark has not yet receded. It is here.", "text_de": "Eine Linie bleibt. An der Decke. Die Mineralablagerung ist frisch – kristallisiert noch. Das Wasser, das dieses Zeichen hinterließ, ist noch nicht zurückgewichen. Es ist hier."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_seal$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "A seal in the floor. Wax over iron, stamped with a symbol that might be a warning or a promise – the distinction depends on which side of the seal you are standing on. Beneath it: the sound of pressure.", "text_de": "Ein Siegel im Boden. Wachs über Eisen, geprägt mit einem Symbol, das eine Warnung oder ein Versprechen sein könnte – die Unterscheidung hängt davon ab, auf welcher Seite des Siegels man steht. Darunter: das Geräusch von Druck."}, "echo": {"text_en": "{agent} examines the seal. Hairline fractures run through the wax like veins. Moisture beads along each crack. The seal is not breaking – it is perspiring.", "text_de": "{agent} untersucht das Siegel. Haarrisse durchziehen das Wachs wie Adern. Feuchtigkeit perlt entlang jedes Risses. Das Siegel bricht nicht – es schwitzt."}, "mutation": {"text_en": "The seal weeps. The wax has softened – not from heat but from patience. Water seeps through the iron beneath in a film so thin it seems like condensation. The boundary is not failing. It is dissolving.", "text_de": "Das Siegel weint. Das Wachs ist weich geworden – nicht durch Hitze, sondern durch Geduld. Wasser sickert durch das Eisen darunter in einem Film so dünn, dass er wie Kondenswasser wirkt. Die Grenze versagt nicht. Sie löst sich auf."}, "climax": {"text_en": "No seal. No hatch. No distinction between above and below. The water is here not because it broke through – because 'through' stopped meaning anything.", "text_de": "Kein Siegel. Keine Luke. Keine Unterscheidung zwischen oben und unten. Das Wasser ist hier, nicht weil es durchbrach – weil »durch« aufgehört hat, etwas zu bedeuten."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_raft$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "Planks lashed together with cable. Not debris – construction. Someone built this deliberately: the knots are tight, the measurements careful. A raft, intended for escape. It is still here. The builder is not.", "text_de": "Planken, mit Kabel zusammengebunden. Kein Treibgut – Konstruktion. Jemand hat das absichtlich gebaut: die Knoten sind fest, die Maße sorgfältig. Ein Floß, gedacht für die Flucht. Es ist noch hier. Der Erbauer nicht."}, "echo": {"text_en": "{agent} finds another fragment. Same cable, same knots. The raft was not broken by the water – it was distributed. The current carried each piece in a different direction.", "text_de": "{agent} findet ein weiteres Fragment. Selbes Kabel, selbe Knoten. Das Floß wurde nicht vom Wasser zerbrochen – es wurde verteilt. Die Strömung trug jedes Stück in eine andere Richtung."}, "mutation": {"text_en": "Fragments in every corner. The water has rearranged them – not into a vessel but into a nest. Something the flood assembled from the wreckage of someone else's escape plan. It floats gently. It is not meant for leaving.", "text_de": "Fragmente in jeder Ecke. Das Wasser hat sie neu angeordnet – nicht zu einem Boot, sondern zu einem Nest. Etwas, das die Flut zusammensetzte aus den Trümmern eines fremden Fluchtplans. Es treibt sanft. Es ist nicht zum Verlassen gedacht."}, "climax": {"text_en": "The raft is whole. Floating in the center of the chamber, riding the surface with the patience of something that belongs here. It was never meant to escape the water. It was meant to join it.", "text_de": "Das Floß ist ganz. Treibend in der Mitte der Kammer, auf der Oberfläche reitend mit der Geduld von etwas, das hierher gehört. Es war nie zur Flucht vor dem Wasser gedacht. Es war gedacht, sich ihm anzuschließen."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_compass$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "A compass, cased in brass. The glass is intact. The needle does not point north – it points down. Straight down, as if the deepest point were the only bearing that still matters.", "text_de": "Ein Kompass, in Messing gefasst. Das Glas ist intakt. Die Nadel zeigt nicht nach Norden – sie zeigt nach unten. Senkrecht, als wäre der tiefste Punkt die einzige Peilung, die noch zählt."}, "echo": {"text_en": "{agent} checks the compass again. The needle still points down, but it trembles now. The thing it is tracking is closer.", "text_de": "{agent} prüft den Kompass erneut. Die Nadel zeigt immer noch nach unten, aber sie zittert jetzt. Das, was sie verfolgt, ist näher."}, "mutation": {"text_en": "The compass glass is fogged from inside. Condensation – the air within the casing has surrendered to moisture. The needle has stopped trembling. It is certain. Whatever lies below has stopped moving.", "text_de": "Das Kompassglas ist von innen beschlagen. Kondenswasser – die Luft im Gehäuse hat sich der Feuchtigkeit ergeben. Die Nadel hat aufgehört zu zittern. Sie ist sicher. Was auch immer darunter liegt, hat aufgehört, sich zu bewegen."}, "climax": {"text_en": "The compass is submerged. Underwater, the needle drifts free – pointing everywhere, pointing nowhere. North was always an agreement. The water has withdrawn its consent.", "text_de": "Der Kompass ist unter Wasser. Untergetaucht treibt die Nadel frei – zeigt überallhin, zeigt nirgendwohin. Norden war immer eine Vereinbarung. Das Wasser hat seine Zustimmung zurückgezogen."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_bottle$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "A bottle. Glass, sealed with wax. Inside: air. Not a message – the medium is the message. Someone preserved the last breath of a dry room.", "text_de": "Eine Flasche. Glas, mit Wachs versiegelt. Darin: Luft. Keine Botschaft – das Medium ist die Botschaft. Jemand hat den letzten Atemzug eines trockenen Raums konserviert."}, "echo": {"text_en": "{agent} spots the bottle again. The current has carried it to the far wall, where it bobs against the surface with the patience of something that has learned to float.", "text_de": "{agent} entdeckt die Flasche wieder. Die Strömung hat sie zur gegenüberliegenden Wand getragen, wo sie gegen die Oberfläche wippt mit der Geduld von etwas, das schwimmen gelernt hat."}, "mutation": {"text_en": "The seal is failing. Air escapes in silver beads that rise through the water and break at the surface without sound. Each bubble smaller than the last. The room is inheriting the bottle's contents.", "text_de": "Das Siegel versagt. Luft entweicht in silbernen Perlen, die durch das Wasser aufsteigen und an der Oberfläche lautlos zerplatzen. Jede Blase kleiner als die vorige. Der Raum erbt den Inhalt der Flasche."}, "climax": {"text_en": "Empty. The glass is full of water now. The air it held is in the room – in the ceiling pocket where the party still stands dry. The bottle kept its promise. It delivered.", "text_de": "Leer. Das Glas ist jetzt voll Wasser. Die Luft, die es hielt, ist im Raum – in der Deckentasche, wo der Trupp noch trocken steht. Die Flasche hat ihr Versprechen gehalten. Sie hat geliefert."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_depth_gauge$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "A gauge, mounted to the wall. Brass, glass-fronted, calibrated in meters. The scale runs from zero to thirty. The current reading: 0.2. The water in this room is dry. The gauge disagrees.", "text_de": "Eine Anzeige, an der Wand montiert. Messing, glasverkleidet, kalibriert in Metern. Die Skala reicht von null bis dreißig. Die aktuelle Anzeige: 0,2. Das Wasser in diesem Raum ist trocken. Die Anzeige widerspricht."}, "echo": {"text_en": "{agent} passes the gauge again. It reads 4.7. The room is dry here. The reading is not wrong – it is premature.", "text_de": "{agent} passiert die Anzeige erneut. Sie zeigt 4,7. Der Raum ist hier trocken. Die Anzeige ist nicht falsch – sie ist verfrüht."}, "mutation": {"text_en": "The gauge reads the exact depth of the current room. To the centimeter. It was calibrated for this moment, in this room, long before either existed. The precision is not mechanical. It is patient.", "text_de": "Die Anzeige zeigt die exakte Tiefe des aktuellen Raums. Auf den Zentimeter. Sie wurde für diesen Moment kalibriert, in diesem Raum, lange bevor es beide gab. Die Präzision ist nicht mechanisch. Sie ist geduldig."}, "climax": {"text_en": "The gauge reads zero. Not because the water has receded. Because the gauge is submerged, and underwater, depth is not a number. It is a condition.", "text_de": "Die Anzeige zeigt null. Nicht weil das Wasser gewichen ist. Weil die Anzeige unter Wasser steht, und unter Wasser ist Tiefe keine Zahl. Sie ist ein Zustand."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_photograph$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "A photograph, curled at the edges from moisture. It shows this room – or one that shares its geometry. In the photograph, the room is dry. Sunlight enters from a window that does not exist here. The photograph remembers what the water has not yet reached.", "text_de": "Eine Fotografie, an den Rändern gewellt von Feuchtigkeit. Sie zeigt diesen Raum – oder einen, der seine Geometrie teilt. In der Fotografie ist der Raum trocken. Sonnenlicht fällt durch ein Fenster, das hier nicht existiert. Die Fotografie erinnert, was das Wasser noch nicht erreicht hat."}, "echo": {"text_en": "{agent} looks at the photograph again. It has changed. Water on the floor now – ankle-deep, the color of weak tea. The photograph is not aging. It is documenting.", "text_de": "{agent} betrachtet die Fotografie erneut. Sie hat sich verändert. Wasser auf dem Boden jetzt – knöcheltief, von der Farbe dünnen Tees. Die Fotografie altert nicht. Sie dokumentiert."}, "mutation": {"text_en": "The photograph and the room are converging. Water level in the image matches the water around the party. The light matches. The geometry matches. The only difference: in the photograph, someone stands where the party stands now. They are looking at a photograph.", "text_de": "Die Fotografie und der Raum nähern sich an. Der Wasserstand im Bild entspricht dem Wasser um den Trupp. Das Licht stimmt. Die Geometrie stimmt. Der einzige Unterschied: in der Fotografie steht jemand dort, wo der Trupp jetzt steht. Sie betrachten eine Fotografie."}, "climax": {"text_en": "The photograph is saturated. The image has dissolved into the water, and the water has absorbed the image. There is no photograph. There is no room that was ever dry. The water remembers. The water has revised.", "text_de": "Die Fotografie ist gesättigt. Das Bild hat sich im Wasser aufgelöst, und das Wasser hat das Bild absorbiert. Es gibt keine Fotografie. Es gibt keinen Raum, der jemals trocken war. Das Wasser erinnert sich. Das Wasser hat revidiert."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$deluge_stone$Q$, $Q$The Deluge$Q$, $JB${"discovery": {"text_en": "A stone. Smooth, the way centuries of current make things smooth. It rests on a dry shelf as if placed there with care. The polish is uniform – no single hand held this. A river did. A river that is not here yet.", "text_de": "Ein Stein. Glatt, so wie Jahrhunderte der Strömung Dinge glatt machen. Er ruht auf einem trockenen Sims, als wäre er mit Bedacht platziert worden. Die Politur ist gleichmäßig – keine einzelne Hand hielt ihn. Ein Fluss tat es. Ein Fluss, der noch nicht hier ist."}, "echo": {"text_en": "{agent} picks up the stone. Heavier. Not because it grew – because the air around it is denser, saturated. The stone accrues the weight of what approaches.", "text_de": "{agent} hebt den Stein auf. Schwerer. Nicht weil er gewachsen ist – weil die Luft um ihn dichter ist, gesättigt. Der Stein sammelt das Gewicht dessen, was sich nähert."}, "mutation": {"text_en": "The stone is wet. Not because the waterline has reached its shelf – the shelf is dry. The stone is wet from within. It remembers the river that shaped it, and the memory is leaking through.", "text_de": "Der Stein ist nass. Nicht weil die Wasserlinie sein Sims erreicht hat – das Sims ist trocken. Der Stein ist nass von innen. Er erinnert sich an den Fluss, der ihn formte, und die Erinnerung sickert durch."}, "climax": {"text_en": "The stone rests on the surface of the water. Not floating – resting. As if the surface were solid, or the stone weightless, or the distinction between sinking and floating were another agreement the water has revoked.", "text_de": "Der Stein ruht auf der Wasseroberfläche. Nicht schwimmend – ruhend. Als wäre die Oberfläche fest, oder der Stein schwerelos, oder die Unterscheidung zwischen Sinken und Schwimmen eine weitere Vereinbarung, die das Wasser widerrufen hat."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_tool$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A tool. Not a tool you recognize – a tool for something that has not been invented yet. It fits the hand uncomfortably well.", "text_de": "Ein Werkzeug. Kein Werkzeug, das ihr erkennt – ein Werkzeug für etwas, das noch nicht erfunden wurde. Es liegt unbequem gut in der Hand."}, "echo": {"text_en": "The tool again. {agent} picks it up. It has changed – the handle is warmer, the edge sharper. It has been practicing.", "text_de": "Das Werkzeug wieder. {agent} hebt es auf. Es hat sich verändert – der Griff ist wärmer, die Kante schärfer. Es hat geübt."}, "mutation": {"text_en": "The tool has split into three. Each version is optimized for a different task. They arranged themselves on the workbench in order of increasing ambition.", "text_de": "Das Werkzeug hat sich in drei geteilt. Jede Version ist für eine andere Aufgabe optimiert. Sie haben sich auf der Werkbank angeordnet, in Reihenfolge zunehmender Ambition."}, "climax": {"text_en": "The tool is gone. In its place: a finished thing. Not what the party built – what the tool built using itself as material.", "text_de": "Das Werkzeug ist weg. An seiner Stelle: ein fertiges Ding. Nicht was der Trupp gebaut hat – was das Werkzeug gebaut hat, mit sich selbst als Material."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_blueprint$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A blueprint, pinned to the wall. The design is for something elegant and impossible. The measurements are in a unit that does not exist.", "text_de": "Eine Blaupause, an die Wand geheftet. Der Entwurf ist für etwas Elegantes und Unmögliches. Die Maße sind in einer Einheit, die es nicht gibt."}, "echo": {"text_en": "{agent} finds the blueprint again. The design has been annotated. The annotations are in {agent}'s handwriting. {agent} does not remember writing them.", "text_de": "{agent} findet die Blaupause wieder. Der Entwurf wurde annotiert. Die Anmerkungen sind in {agent}s Handschrift. {agent} erinnert sich nicht, sie geschrieben zu haben."}, "mutation": {"text_en": "The blueprint has folded itself into a three-dimensional model. It rotates slowly in the air, demonstrating its own construction sequence.", "text_de": "Die Blaupause hat sich zu einem dreidimensionalen Modell gefaltet. Es rotiert langsam in der Luft und demonstriert seine eigene Konstruktionssequenz."}, "climax": {"text_en": "The model is building itself. Layer by layer, from the inside out. It does not need the party. It never needed the party.", "text_de": "Das Modell baut sich selbst. Schicht für Schicht, von innen nach außen. Es braucht den Trupp nicht. Es hat den Trupp nie gebraucht."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_crucible_fragment$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A shard of a crucible. Still warm. Inside, residue of an alloy that does not exist in any catalogue.", "text_de": "Eine Scherbe eines Tiegels. Noch warm. Darin: Rückstände einer Legierung, die in keinem Katalog existiert."}, "echo": {"text_en": "The shard is larger now. Or {agent} is remembering it differently. The residue inside has crystallized into a pattern that looks like instructions.", "text_de": "Die Scherbe ist jetzt größer. Oder {agent} erinnert sich anders an sie. Die Rückstände darin haben sich zu einem Muster kristallisiert, das wie Anweisungen aussieht."}, "mutation": {"text_en": "The shard has reconstructed itself into a complete crucible. It is hot. It is ready. It contains, already, the ghost of something that wants to be made.", "text_de": "Die Scherbe hat sich zu einem kompletten Tiegel rekonstruiert. Er ist heiß. Er ist bereit. Er enthält bereits den Geist von etwas, das gemacht werden will."}, "climax": {"text_en": "The crucible overflows. What pours out is not metal – it is light. The light solidifies into a shape the party almost recognizes.", "text_de": "Der Tiegel läuft über. Was herausfließt, ist kein Metall – es ist Licht. Das Licht verfestigt sich zu einer Form, die der Trupp fast erkennt."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_apprentice_journal$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A journal. The entries describe experiments: temperatures, durations, component ratios. The last entry reads: 'Tomorrow I try the combination the workshop suggested.'", "text_de": "Ein Journal. Die Einträge beschreiben Experimente: Temperaturen, Dauer, Komponentenverhältnisse. Der letzte Eintrag lautet: »Morgen versuche ich die Kombination, die die Werkstatt vorgeschlagen hat.«"}, "echo": {"text_en": "Another journal. Same handwriting. But {agent} notices: the experiments are more ambitious. The margins contain doodles of impossible machines.", "text_de": "Ein weiteres Journal. Dieselbe Handschrift. Aber {agent} bemerkt: Die Experimente sind ambitionierter. Die Ränder enthalten Skizzen unmöglicher Maschinen."}, "mutation": {"text_en": "The journal writes itself now. Pages fill as the party watches. The experiments described are the party's own. Documented before they happened.", "text_de": "Das Journal schreibt sich jetzt selbst. Seiten füllen sich, während der Trupp zusieht. Die beschriebenen Experimente sind die eigenen des Trupps. Dokumentiert, bevor sie stattfanden."}, "climax": {"text_en": "The last page of the journal contains one sentence: 'They made the right thing.' It is written in the future tense.", "text_de": "Die letzte Seite des Journals enthält einen Satz: »Sie haben das Richtige gemacht.« Er ist im Futur geschrieben."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_filament$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A filament. Thin as intention, strung between two posts that hold it with the delicacy of an experiment not yet concluded. It hums – not with current but with readiness. It is waiting to conduct.", "text_de": "Ein Filament. Dünn wie eine Absicht, gespannt zwischen zwei Pfosten, die es halten mit der Behutsamkeit eines noch nicht abgeschlossenen Experiments. Es summt – nicht mit Strom, sondern mit Bereitschaft. Es wartet darauf, zu leiten."}, "echo": {"text_en": "{agent} finds the filament again. Brighter. It has learned something between rooms – the hum is steadier, more purposeful. Something passed through it. It liked it.", "text_de": "{agent} findet das Filament wieder. Heller. Es hat etwas gelernt zwischen den Räumen – das Summen ist stetiger, zielgerichteter. Etwas ist hindurchgegangen. Es hat ihm gefallen."}, "mutation": {"text_en": "The filament has branched. A network now, strung between every surface, humming with the harmonics of connection. It conducts nothing the party sent. It is conducting itself.", "text_de": "Das Filament hat sich verzweigt. Ein Netzwerk jetzt, gespannt zwischen jeder Fläche, summend mit den Obertönen der Verbindung. Es leitet nichts, was der Trupp geschickt hat. Es leitet sich selbst."}, "climax": {"text_en": "The filament glows. Steady, warm, precise. It does not illuminate the room – it illuminates the pattern. The pattern is the party's route through the dungeon. The filament knew it before they walked it.", "text_de": "Das Filament glüht. Stetig, warm, präzise. Es erleuchtet nicht den Raum – es erleuchtet das Muster. Das Muster ist die Route des Trupps durch den Dungeon. Das Filament kannte sie, bevor sie sie gingen."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_scale_model$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A model on the workbench. Small, intricate, assembled from wire and crystal and something that looks like compressed light. It is a model of a machine that does not exist. The craftsmanship suggests it should.", "text_de": "Ein Modell auf der Werkbank. Klein, filigran, zusammengesetzt aus Draht und Kristall und etwas, das wie komprimiertes Licht aussieht. Es ist das Modell einer Maschine, die nicht existiert. Die Handwerkskunst legt nahe, dass sie es sollte."}, "echo": {"text_en": "{agent} examines the model. It has grown. Not in size – in detail. Components that were abstract are now precise. The model is refining itself.", "text_de": "{agent} untersucht das Modell. Es ist gewachsen. Nicht in der Größe – im Detail. Komponenten, die abstrakt waren, sind jetzt präzise. Das Modell verfeinert sich selbst."}, "mutation": {"text_en": "The model is larger than the workbench now. It has outgrown its frame. Parts of it extend beyond the table's edge, hovering in place as if scale were a suggestion it has decided to decline.", "text_de": "Das Modell ist jetzt größer als die Werkbank. Es ist über seinen Rahmen hinausgewachsen. Teile davon ragen über den Tischrand hinaus, schwebend, als wäre Maßstab ein Vorschlag, den es abzulehnen beschlossen hat."}, "climax": {"text_en": "The model is the room. The room is the model. The machine it described has been built – around you, with you inside it. The scale was always 1:1.", "text_de": "Das Modell ist der Raum. Der Raum ist das Modell. Die Maschine, die es beschrieb, wurde gebaut – um euch, mit euch darin. Der Maßstab war immer 1:1."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_alloy$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A sample of metal on the bench. Not a single element – a blend, still warm from the fusion. The surface shifts color when observed from different angles. The alloy has not decided what it wants to be.", "text_de": "Eine Metallprobe auf der Bank. Kein einzelnes Element – eine Legierung, noch warm von der Verschmelzung. Die Oberfläche wechselt die Farbe je nach Blickwinkel. Die Legierung hat noch nicht entschieden, was sie sein will."}, "echo": {"text_en": "{agent} picks up the alloy. It has settled – one color now, one texture. But it is warm in exactly the places where {agent}'s grip falls. It is accommodating.", "text_de": "{agent} hebt die Legierung auf. Sie hat sich beruhigt – eine Farbe jetzt, eine Textur. Aber sie ist genau dort warm, wo {agent}s Griff fällt. Sie fügt sich."}, "mutation": {"text_en": "The alloy has divided itself. Three pieces, each a different composition, each optimized for a property the original lacked: hardness, conductivity, resonance. It did not wait to be forged. It forged itself.", "text_de": "Die Legierung hat sich geteilt. Drei Stücke, jedes eine andere Zusammensetzung, jedes optimiert für eine Eigenschaft, die dem Original fehlte: Härte, Leitfähigkeit, Resonanz. Sie hat nicht gewartet, geschmiedet zu werden. Sie hat sich selbst geschmiedet."}, "climax": {"text_en": "The alloy is gone. In its place: a tool that fits no category in the workshop's index. It is made of everything it tried. The forge did not make this. The material did.", "text_de": "Die Legierung ist weg. An ihrer Stelle: ein Werkzeug, das in keine Kategorie des Werkstattverzeichnisses passt. Es besteht aus allem, was es versucht hat. Die Schmiede hat das nicht gemacht. Das Material schon."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$prometheus_flame$Q$, $Q$The Prometheus$Q$, $JB${"discovery": {"text_en": "A flame. Small, contained in a glass crucible. It burns without fuel – not magical, but self-sustaining. The combustion feeds on its own product. It is a proof of concept for something that should not work.", "text_de": "Eine Flamme. Klein, in einem Glastiegel. Sie brennt ohne Brennstoff – nicht magisch, sondern selbsterhaltend. Die Verbrennung nährt sich von ihrem eigenen Produkt. Sie ist ein Machbarkeitsnachweis für etwas, das nicht funktionieren sollte."}, "echo": {"text_en": "{agent} passes the flame. It has changed color – responding to the party's proximity the way a forge responds to the bellows. It is not warming itself. It is warming to them.", "text_de": "{agent} passiert die Flamme. Sie hat ihre Farbe gewechselt – reagierend auf die Nähe des Trupps, wie eine Schmiede auf den Blasebalg reagiert. Sie wärmt nicht sich selbst. Sie erwärmt sich für sie."}, "mutation": {"text_en": "The crucible is cracked. The flame has outgrown it – not violently, but persistently. Glass cannot contain what the flame has become. It burns freestanding now, feeding on air that tastes of ambition.", "text_de": "Der Tiegel hat Risse. Die Flamme ist ihm entwachsen – nicht gewaltsam, aber beharrlich. Glas kann nicht enthalten, was die Flamme geworden ist. Sie brennt jetzt freistehend, genährt von Luft, die nach Ambition schmeckt."}, "climax": {"text_en": "The flame is the room's only light. It has consumed neither fuel nor air nor patience. It is the oldest fire in the workshop – the one that was stolen, and refused to go out.", "text_de": "Die Flamme ist das einzige Licht des Raums. Sie hat weder Brennstoff noch Luft noch Geduld verbraucht. Sie ist das älteste Feuer in der Werkstatt – das, das gestohlen wurde und sich weigerte zu erlöschen."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_mirror_shard$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "A shard of mirror, propped against the wall. It reflects the room – but the reflection is a fraction of a second ahead. In the glass, the party has already moved to where they are about to stand.", "text_de": "Eine Spiegelscherbe, an die Wand gelehnt. Sie reflektiert den Raum – aber die Spiegelung ist einen Sekundenbruchteil voraus. Im Glas hat der Trupp sich bereits bewegt, dorthin, wo er gleich stehen wird."}, "echo": {"text_en": "{agent} looks into the shard. The shard looks back. The reflection is attentive – not passive, not copying. Observing.", "text_de": "{agent} blickt in die Scherbe. Die Scherbe blickt zurück. Die Reflexion ist aufmerksam – nicht passiv, nicht kopierend. Beobachtend."}, "mutation": {"text_en": "The shard reflects a room that does not match this one. Same geometry, different contents. The other room is furnished with choices the party did not make. It is more complete. It looks inhabited.", "text_de": "Die Scherbe reflektiert einen Raum, der nicht mit diesem übereinstimmt. Selbe Geometrie, anderer Inhalt. Der andere Raum ist eingerichtet mit Entscheidungen, die der Trupp nicht getroffen hat. Er ist vollständiger. Er wirkt bewohnt."}, "climax": {"text_en": "The shard reflects everything. Every version of this room – visited, unvisited, imagined, remembered. The party is in all of them. The party is all of them.", "text_de": "Die Scherbe reflektiert alles. Jede Version dieses Raums – besucht, unbesucht, vorgestellt, erinnert. Der Trupp ist in allen. Der Trupp ist alle."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_philemon_feather$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "A feather. Iridescent, shifting between colors that have no names in any index. It does not belong to any creature the party has catalogued. It belongs to something that has not been observed yet – only dreamt.", "text_de": "Eine Feder. Schillernd, wechselnd zwischen Farben, die in keinem Index Namen haben. Sie gehört keinem Wesen, das der Trupp katalogisiert hat. Sie gehört etwas, das noch nicht beobachtet wurde – nur geträumt."}, "echo": {"text_en": "{agent} picks up the feather. A thought arrives – unbidden, fully formed, in a voice that is not {agent}'s own. The thought is a stranger in the room. It does not leave.", "text_de": "{agent} hebt die Feder auf. Ein Gedanke kommt – ungerufen, vollständig geformt, in einer Stimme, die nicht {agent}s eigene ist. Der Gedanke ist ein Fremder im Raum. Er geht nicht."}, "mutation": {"text_en": "The feather writes. Not with ink – with attention. Where it rests, the surface remembers things that have not happened yet. The writing is precise. The writing is in the party's hand.", "text_de": "Die Feder schreibt. Nicht mit Tinte – mit Aufmerksamkeit. Wo sie liegt, erinnert die Fläche sich an Dinge, die noch nicht geschehen sind. Die Schrift ist präzise. Die Schrift ist in der Hand des Trupps."}, "climax": {"text_en": "The feather is the party's own thought, wearing a body it borrowed from outside. The voice was always theirs. The stranger was always home.", "text_de": "Die Feder ist der eigene Gedanke des Trupps, der einen Körper trägt, den er sich von außen geliehen hat. Die Stimme war immer ihre. Der Fremde war immer zuhause."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_madeleine$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "A small object on a shelf. Unremarkable in form – but touching it triggers something involuntary: a sensation that does not belong to this room, from a time the party has not lived. The object is a key to a lock that is not here.", "text_de": "Ein kleines Objekt auf einem Regal. Unscheinbar in der Form – aber es zu berühren löst etwas Unwillkürliches aus: eine Empfindung, die nicht zu diesem Raum gehört, aus einer Zeit, die der Trupp nicht gelebt hat. Das Objekt ist ein Schlüssel zu einem Schloss, das nicht hier ist."}, "echo": {"text_en": "{agent} holds the object again. A memory surfaces – not from {agent}'s history. From the dungeon's. The memory is warm and specific and does not belong here.", "text_de": "{agent} hält das Objekt erneut. Eine Erinnerung taucht auf – nicht aus {agent}s Geschichte. Aus der des Dungeons. Die Erinnerung ist warm und spezifisch und gehört nicht hierher."}, "mutation": {"text_en": "The object has changed texture. It feels like every significant thing the party has ever touched – simultaneously. The sensation accumulates. The memory is not playback. It is reconstruction, and each touch rebuilds it differently.", "text_de": "Das Objekt hat seine Textur verändert. Es fühlt sich an wie jedes bedeutsame Ding, das der Trupp je berührt hat – gleichzeitig. Die Empfindung akkumuliert. Die Erinnerung ist keine Wiedergabe. Sie ist Rekonstruktion, und jede Berührung baut sie anders auf."}, "climax": {"text_en": "The object dissolves on contact. What it held was never inside it. It was inside the party – waiting for a shape to give it permission to surface.", "text_de": "Das Objekt löst sich bei Berührung auf. Was es hielt, war nie in ihm. Es war im Trupp – wartend auf eine Form, die ihm Erlaubnis gab aufzutauchen."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_two_clocks$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "Two clocks on the wall. They show different times. Both are running. Both are precise. Neither is wrong. The room contains two versions of now, and they disagree.", "text_de": "Zwei Uhren an der Wand. Sie zeigen verschiedene Zeiten. Beide laufen. Beide sind präzise. Keine ist falsch. Der Raum enthält zwei Versionen von Jetzt, und sie widersprechen sich."}, "echo": {"text_en": "{agent} checks both clocks. The gap between them has widened. The left one runs at the pace of observation. The right one runs at the pace of experience. They are separating.", "text_de": "{agent} prüft beide Uhren. Der Abstand zwischen ihnen hat sich vergrößert. Die linke läuft im Tempo der Beobachtung. Die rechte im Tempo der Erfahrung. Sie trennen sich."}, "mutation": {"text_en": "The outer clock has stopped. The inner clock accelerates – minutes condensing into seconds, hours into moments. The room is experiencing itself faster than the party can observe it.", "text_de": "Die äußere Uhr ist stehen geblieben. Die innere Uhr beschleunigt – Minuten verdichten sich zu Sekunden, Stunden zu Momenten. Der Raum erlebt sich selbst schneller, als der Trupp ihn beobachten kann."}, "climax": {"text_en": "Both clocks show the same time. The party cannot tell which one yielded. The two versions of now have agreed. What they agreed on is: the party was always here.", "text_de": "Beide Uhren zeigen dieselbe Zeit. Der Trupp kann nicht sagen, welche nachgegeben hat. Die zwei Versionen von Jetzt haben sich geeinigt. Worauf sie sich geeinigt haben: der Trupp war immer hier."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_cave_shadow$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "A shadow on the wall. It moves independently of any light source – not flickering, but gesturing. The shadow is describing something the party cannot see. It has been at this for a long time.", "text_de": "Ein Schatten an der Wand. Er bewegt sich unabhängig von jeder Lichtquelle – nicht flackernd, sondern gestikulierend. Der Schatten beschreibt etwas, das der Trupp nicht sehen kann. Er tut das seit langem."}, "echo": {"text_en": "{agent} steps between the shadow and the wall. The shadow does not change. {agent} is not casting it. Something else is. Something behind the light.", "text_de": "{agent} tritt zwischen den Schatten und die Wand. Der Schatten verändert sich nicht. {agent} wirft ihn nicht. Etwas anderes tut es. Etwas hinter dem Licht."}, "mutation": {"text_en": "The shadow shows events from other rooms. Encounters the party has not yet reached, doors they have not yet opened. The shadow knows the dungeon the way a dreamer knows the dream – from above, all at once, without sequence.", "text_de": "Der Schatten zeigt Ereignisse aus anderen Räumen. Begegnungen, die der Trupp noch nicht erreicht hat, Türen, die er noch nicht geöffnet hat. Der Schatten kennt den Dungeon, wie ein Träumender den Traum kennt – von oben, alles gleichzeitig, ohne Reihenfolge."}, "climax": {"text_en": "The shadow is the party. Projected not by light but by awareness. The wall was never a surface. It was always a mirror facing inward.", "text_de": "Der Schatten ist der Trupp. Projiziert nicht von Licht, sondern von Bewusstsein. Die Wand war nie eine Fläche. Sie war immer ein Spiegel, der nach innen zeigt."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_empathy_box$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "A device with two handles, mounted on a pedestal. The handles are smooth from use. A residue of warmth clings to the grips – not from heat but from contact. Someone held on. Recently.", "text_de": "Ein Gerät mit zwei Griffen, auf einem Podest montiert. Die Griffe sind glatt vom Gebrauch. Ein Rest von Wärme haftet an den Griffen – nicht von Hitze, sondern von Berührung. Jemand hat sich festgehalten. Kürzlich."}, "echo": {"text_en": "{agent} touches the handles. For a moment: every agent's perception, simultaneously. The room seen from four angles. The moment passes. The memory does not.", "text_de": "{agent} berührt die Griffe. Für einen Moment: die Wahrnehmung jedes Agenten, gleichzeitig. Der Raum aus vier Blickwinkeln gesehen. Der Moment vergeht. Die Erinnerung nicht."}, "mutation": {"text_en": "The handles are warm. Someone else is grasping them from the other side – from inside the device, from inside the connection itself. The grip is patient. It has been waiting.", "text_de": "Die Griffe sind warm. Jemand anderes hält sie von der anderen Seite – aus dem Inneren des Geräts, aus dem Inneren der Verbindung selbst. Der Griff ist geduldig. Er hat gewartet."}, "climax": {"text_en": "The device is empty. No mechanism inside. The shared perception no longer requires hardware. It requires only the party. The connection was never in the box.", "text_de": "Das Gerät ist leer. Kein Mechanismus darin. Die geteilte Wahrnehmung benötigt keine Apparatur mehr. Sie benötigt nur den Trupp. Die Verbindung war nie in der Box."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_unicorn_skull$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "A skull. Bone-white, smooth, from no creature in any catalogue. The cranium is shaped for a brain larger than biology typically permits. It is heavy with something that is not mass.", "text_de": "Ein Schädel. Knochenweiß, glatt, von keiner Kreatur in irgendeinem Katalog. Das Cranium ist geformt für ein Gehirn größer als Biologie typischerweise erlaubt. Er ist schwer von etwas, das nicht Masse ist."}, "echo": {"text_en": "{agent} holds the skull. Images leak through – not memories but impressions. Scenes without context, emotions without events. Old dreams, stored in bone.", "text_de": "{agent} hält den Schädel. Bilder sickern durch – keine Erinnerungen, sondern Eindrücke. Szenen ohne Kontext, Emotionen ohne Ereignisse. Alte Träume, gespeichert in Knochen."}, "mutation": {"text_en": "The skull is heavier. It has absorbed the party's own dreams – not by force but by proximity. The bone is a medium. It stores what the waking mind discards.", "text_de": "Der Schädel ist schwerer. Er hat die Träume des Trupps absorbiert – nicht mit Gewalt, sondern durch Nähe. Der Knochen ist ein Medium. Er speichert, was der wache Verstand verwirft."}, "climax": {"text_en": "The skull hums. Not with sound – with recognition. It knows the party. The party's own unconscious, given a shape that outlasts forgetting.", "text_de": "Der Schädel summt. Nicht mit Klang – mit Wiedererkennung. Er kennt den Trupp. Das eigene Unbewusste des Trupps, dem eine Form gegeben wurde, die das Vergessen überdauert."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$awakening_doorkeeper$Q$, $Q$The Awakening$Q$, $JB${"discovery": {"text_en": "A figure beside an open door. The figure does not block entry – it simply stands, patient, as if arrival were the only purpose of waiting. The door was always open. The figure has never closed it.", "text_de": "Eine Gestalt neben einer offenen Tür. Die Gestalt versperrt nicht den Eintritt – sie steht einfach, geduldig, als wäre Ankunft der einzige Zweck des Wartens. Die Tür war immer offen. Die Gestalt hat sie nie geschlossen."}, "echo": {"text_en": "{agent} addresses the figure. It does not respond with words – it responds with stillness. The kind of stillness that is itself an answer.", "text_de": "{agent} spricht die Gestalt an. Sie antwortet nicht mit Worten – sie antwortet mit Stille. Die Art von Stille, die selbst eine Antwort ist."}, "mutation": {"text_en": "The figure has aged. The door has not. The figure has been waiting for the party's entire existence. The patience is not servitude. It is faith.", "text_de": "Die Gestalt ist gealtert. Die Tür nicht. Die Gestalt hat auf den Trupp gewartet für dessen gesamte Existenz. Die Geduld ist keine Knechtschaft. Sie ist Glaube."}, "climax": {"text_en": "The figure steps aside. There was never a barrier. The door was made for the party alone. The only thing between the party and the door was the belief that something stood between them.", "text_de": "Die Gestalt tritt zur Seite. Es gab nie eine Barriere. Die Tür wurde nur für den Trupp gemacht. Das Einzige zwischen dem Trupp und der Tür war der Glaube, dass etwas dazwischen stand."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_faction_banner$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A banner. The insignia is familiar – from two rooms ago, where it meant something different.", "text_de": "Ein Banner. Das Abzeichen ist vertraut – aus zwei Räumen zuvor, wo es etwas anderes bedeutete."}, "echo": {"text_en": "The banner has been turned inside out. The same insignia, reversed. A faction's mirror image.", "text_de": "Das Banner wurde umgedreht. Dasselbe Abzeichen, gespiegelt. Das Spiegelbild einer Fraktion."}, "mutation": {"text_en": "The banner bears no insignia now. It bears a mirror. The mirror reflects whoever looks at it in faction colors.", "text_de": "Das Banner trägt jetzt kein Abzeichen. Es trägt einen Spiegel. Der Spiegel reflektiert jeden, der hinsieht, in Fraktionsfarben."}, "climax": {"text_en": "The banner is blank. All factions have claimed it. All factions have abandoned it. It flies for no one.", "text_de": "Das Banner ist leer. Alle Fraktionen haben es beansprucht. Alle Fraktionen haben es aufgegeben. Es weht für niemanden."}}$JB$::jsonb, 0) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_decree_stone$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A stone tablet with a decree. The ink is fresh. The decree is reasonable.", "text_de": "Eine Steintafel mit einem Dekret. Die Tinte ist frisch. Das Dekret ist vernünftig."}, "echo": {"text_en": "The decree has been amended. The amendment contradicts the original. Both remain binding.", "text_de": "Das Dekret wurde ergänzt. Die Ergänzung widerspricht dem Original. Beide bleiben bindend."}, "mutation": {"text_en": "The stone now bears three decrees. They form a triangle of mutual contradiction. Each abolishes the one before it. The last abolishes itself.", "text_de": "Der Stein trägt jetzt drei Dekrete. Sie bilden ein Dreieck gegenseitigen Widerspruchs. Jedes hebt das vorige auf. Das letzte hebt sich selbst auf."}, "climax": {"text_en": "The decree stone is blank. Not erased – never inscribed. The authority to decree has been decreed nonexistent.", "text_de": "Der Dekretstein ist leer. Nicht gelöscht – nie beschrieben. Die Autorität zu dekretieren wurde für inexistent dekretiert."}}$JB$::jsonb, 1) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_informers_clipboard$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A clipboard with names. Some checked off. The party's names are listed but not yet checked.", "text_de": "Ein Klemmbrett mit Namen. Einige abgehakt. Die Namen der Gruppe sind aufgelistet, aber noch nicht abgehakt."}, "echo": {"text_en": "The clipboard has grown. More names. The handwriting changes – multiple informers, same list.", "text_de": "Das Klemmbrett ist gewachsen. Mehr Namen. Die Handschrift wechselt – mehrere Spitzel, dieselbe Liste."}, "mutation": {"text_en": "The informer's name is on the list now. The informer is being informed on. The system is recursive.", "text_de": "Der Name des Spitzels steht jetzt auf der Liste. Der Spitzel wird bespitzelt. Das System ist rekursiv."}, "climax": {"text_en": "Every name on the list is checked off. The list continues. There are no names left to check. The checking continues.", "text_de": "Jeder Name auf der Liste ist abgehakt. Die Liste geht weiter. Es gibt keine Namen mehr zum Abhaken. Das Abhaken geht weiter."}}$JB$::jsonb, 2) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_trial_chair$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "An empty chair in the center of a room. The room is arranged for a tribunal. The chair is for the accused.", "text_de": "Ein leerer Stuhl in der Mitte eines Raums. Der Raum ist für ein Tribunal eingerichtet. Der Stuhl ist für den Angeklagten."}, "echo": {"text_en": "The chair has been occupied. Recently. The warmth is still there. The verdict has already been passed.", "text_de": "Der Stuhl war besetzt. Kürzlich. Die Wärme ist noch da. Das Urteil wurde bereits gefällt."}, "mutation": {"text_en": "The chair faces a mirror now. The accused watches their own trial. The transcript writes itself in the margins. Every word is accurate. Every word is a lie.", "text_de": "Der Stuhl steht jetzt vor einem Spiegel. Der Angeklagte beobachtet seinen eigenen Prozess. Das Protokoll schreibt sich in den Rändern fort. Jedes Wort ist akkurat. Jedes Wort ist eine Lüge."}, "climax": {"text_en": "The chair is for the judge now. The accused is gone. The judge sits and realizes: the next trial is their own.", "text_de": "Der Stuhl ist jetzt für den Richter. Der Angeklagte ist weg. Der Richter sitzt und erkennt: der nächste Prozess ist der eigene."}}$JB$::jsonb, 3) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_mirror_corridor$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "Mirrors on both walls. The reflections are accurate. Suspiciously accurate.", "text_de": "Spiegel an beiden Wänden. Die Spiegelungen sind exakt. Verdächtig exakt."}, "echo": {"text_en": "The reflections are slightly ahead of the party. They know where the party is going before the party does.", "text_de": "Die Spiegelungen sind der Gruppe leicht voraus. Sie wissen, wohin die Gruppe geht, bevor die Gruppe es weiß."}, "mutation": {"text_en": "The reflections wear different faction insignia than the party. The mirror shows allegiance, not appearance.", "text_de": "Die Spiegelungen tragen andere Fraktionsabzeichen als die Gruppe. Der Spiegel zeigt Treue, nicht Aussehen."}, "climax": {"text_en": "The mirrors face each other. Infinite recursion. Infinite factions. The Pretender is in every reflection.", "text_de": "Die Spiegel stehen sich gegenüber. Unendliche Rekursion. Unendliche Fraktionen. Der Prätendent ist in jeder Spiegelung."}}$JB$::jsonb, 4) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_propaganda_poster$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "A poster. The message is clear, the design effective. The font is authoritative. The colors are calming. It does not ask you to agree. It assumes you already do.", "text_de": "Ein Plakat. Die Botschaft ist klar, das Design wirkungsvoll. Die Schrift ist autoritär. Die Farben beruhigend. Es bittet nicht um Zustimmung. Es setzt sie voraus."}, "echo": {"text_en": "The poster has been pasted over with a new one. The new poster says the opposite. The adhesive is the same.", "text_de": "Das Plakat wurde mit einem neuen überklebt. Das neue Plakat sagt das Gegenteil. Der Klebstoff ist derselbe."}, "mutation": {"text_en": "Both posters are visible now, layered. The contradiction is the message. Believe both. Believe neither. The skill is not choosing – it is holding both at once.", "text_de": "Beide Plakate sind jetzt sichtbar, geschichtet. Der Widerspruch ist die Botschaft. Glaube beides. Glaube nichts. Die Kunst ist nicht das Wählen – es ist das gleichzeitige Halten."}, "climax": {"text_en": "The poster is blank. Not torn down – never printed. The propaganda has moved from paper into the air itself.", "text_de": "Das Plakat ist leer. Nicht abgerissen – nie gedruckt. Die Propaganda ist vom Papier in die Luft selbst übergegangen."}}$JB$::jsonb, 5) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_scales_of_justice$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "Balanced scales. Both pans empty. The balance is perfect because nothing is being weighed.", "text_de": "Ausbalancierte Waage. Beide Schalen leer. Die Balance ist perfekt, weil nichts gewogen wird."}, "echo": {"text_en": "One pan holds a faction seal. The other holds a different faction seal. They weigh exactly the same.", "text_de": "Eine Schale hält ein Fraktionssiegel. Die andere ein anderes Fraktionssiegel. Sie wiegen genau gleich."}, "mutation": {"text_en": "A thumb on the scale. Whose thumb? The mirror behind the scales does not show a hand.", "text_de": "Ein Daumen auf der Waage. Wessen Daumen? Der Spiegel hinter der Waage zeigt keine Hand."}, "climax": {"text_en": "The scales tip. Both pans hit the ground simultaneously. Justice is not blind – justice has been dismissed.", "text_de": "Die Waage kippt. Beide Schalen treffen gleichzeitig den Boden. Gerechtigkeit ist nicht blind – Gerechtigkeit wurde abgesetzt."}}$JB$::jsonb, 6) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_anchor_objects (id, archetype, phases, sort_order) VALUES ($Q$overthrow_colossus_pedestal$Q$, $Q$The Overthrow$Q$, $JB${"discovery": {"text_en": "An empty pedestal. The stone is scarred where something massive stood – not a statue but a presence, large enough to cast a shadow that is still here. The shadow has not noticed it is empty.", "text_de": "Ein leerer Sockel. Der Stein ist vernarbt, wo etwas Massives stand – keine Statue, sondern eine Präsenz, groß genug, um einen Schatten zu werfen, der immer noch hier ist. Der Schatten hat nicht bemerkt, dass er leer ist."}, "echo": {"text_en": "{agent} reads the inscription on the pedestal. It says: 'The Colossus stands because you carry it.' Below, in a different hand: 'Stop carrying.'", "text_de": "{agent} liest die Inschrift auf dem Sockel. Sie lautet: »Der Koloss steht, weil ihr ihn tragt.« Darunter, in einer anderen Handschrift: »Hört auf zu tragen.«"}, "mutation": {"text_en": "Cracks in the pedestal – radiating downward. The Colossus did not fall. It was pulled. From below. By the hands that built it. The stone remembers every grip.", "text_de": "Risse im Sockel – nach unten strahlend. Der Koloss ist nicht gefallen. Er wurde gezogen. Von unten. Von den Händen, die ihn gebaut haben. Der Stein erinnert sich an jeden Griff."}, "climax": {"text_en": "The pedestal is being rebuilt. Fresh mortar, new inscription, same dimensions. The builders are the ones who pulled the last one down. They have not noticed. The blueprints are the same.", "text_de": "Der Sockel wird wieder aufgebaut. Frischer Mörtel, neue Inschrift, selbe Maße. Die Baumeister sind die, die den letzten heruntergerissen haben. Sie haben es nicht bemerkt. Die Baupläne sind dieselben."}}$JB$::jsonb, 7) ON CONFLICT (archetype, id) DO UPDATE SET phases = EXCLUDED.phases, sort_order = EXCLUDED.sort_order;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Deluge$Q$, 0, $Q$The water is present but patient. It laps at the lowest edges of the corridor with the rhythm of something that has not yet decided to rise. The sound is almost gentle.$Q$, $Q$Das Wasser ist da, aber geduldig. Es leckt an den niedrigsten Kanten des Korridors im Rhythmus von etwas, das sich noch nicht entschieden hat zu steigen. Das Geräusch ist beinahe sanft.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Deluge$Q$, 1, $Q$The water has risen. Not gradually – in the time between noticing and measuring, it gained another centimeter. The current has found a direction. It is moving inward.$Q$, $Q$Das Wasser ist gestiegen. Nicht allmählich – in der Zeit zwischen Bemerken und Messen hat es einen weiteren Zentimeter gewonnen. Die Strömung hat eine Richtung gefunden. Sie bewegt sich nach innen.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Deluge$Q$, 2, $Q$The water is no longer patient. It pushes. The sound has changed from lapping to pressure – the low, constant hum of volume looking for somewhere to go. It is finding places.$Q$, $Q$Das Wasser ist nicht mehr geduldig. Es drängt. Das Geräusch hat sich von Plätschern zu Druck verändert – das tiefe, gleichmäßige Summen von Volumen, das einen Ort sucht. Es findet welche.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Deluge$Q$, 3, $Q$The water is here. Not rising – arrived. It fills the space the way an answer fills a question: completely, and with the weight of having always been inevitable.$Q$, $Q$Das Wasser ist da. Nicht steigend – angekommen. Es füllt den Raum wie eine Antwort eine Frage füllt: vollständig, und mit dem Gewicht, immer unvermeidlich gewesen zu sein.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 0, $Q$The rooms are quiet in a way that suggests sleep – not absence but suspension. The walls register the party's presence the way a dreamer registers a distant sound.$Q$, $Q$Die Räume sind still auf eine Art, die Schlaf nahelegt – nicht Abwesenheit, sondern Suspension. Die Wände registrieren die Präsenz des Trupps wie ein Träumender ein fernes Geräusch registriert.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 1, $Q$Something has shifted. The corridors respond a fraction faster now – lights adjust before the party rounds a corner, doors settle into frames as if preparing. The dungeon is stirring.$Q$, $Q$Etwas hat sich verschoben. Die Korridore reagieren einen Bruchteil schneller jetzt – Lichter passen sich an, bevor der Trupp um eine Ecke biegt, Türen fügen sich in Rahmen, als bereiteten sie sich vor. Der Dungeon erwacht.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 2, $Q$The dungeon is watching. Not with eyes – with attention. The geometry of each room seems arranged for observation. The party is not exploring. The party is being perceived.$Q$, $Q$Der Dungeon beobachtet. Nicht mit Augen – mit Aufmerksamkeit. Die Geometrie jedes Raums wirkt wie für Beobachtung arrangiert. Der Trupp erkundet nicht. Der Trupp wird wahrgenommen.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Awakening$Q$, 3, $Q$The dungeon remembers. Every room the party has entered, every choice they have made – the walls hold it all, and they are no longer passive. What was asleep is awake. What is awake is thinking.$Q$, $Q$Der Dungeon erinnert sich. Jeden Raum, den der Trupp betreten hat, jede Entscheidung – die Wände halten alles, und sie sind nicht mehr passiv. Was schlief, ist wach. Was wach ist, denkt.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 0, $Q$The corridors are ordered. Signs point in consistent directions. The insignia on the walls match. Someone is in charge here, and the architecture believes them.$Q$, $Q$Die Korridore sind geordnet. Schilder weisen in konsistente Richtungen. Die Abzeichen an den Wänden stimmen überein. Jemand hat hier das Sagen, und die Architektur glaubt ihnen.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 1, $Q$A sign has been corrected. The original direction is visible beneath the amendment. Two versions of authority overlap – the first confident, the second insistent.$Q$, $Q$Ein Schild wurde korrigiert. Die ursprüngliche Richtung ist unter der Änderung sichtbar. Zwei Versionen von Autorität überlagern sich – die erste zuversichtlich, die zweite bestimmt.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 2, $Q$The signs contradict each other. Three factions have posted directions to the same corridor, each claiming a different destination. The architecture has stopped choosing.$Q$, $Q$Die Schilder widersprechen einander. Drei Fraktionen haben Wegweiser zum selben Korridor angebracht, jede mit einem anderen Ziel. Die Architektur hat aufgehört zu wählen.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
INSERT INTO dungeon_barometer_texts (archetype, tier, text_en, text_de) VALUES ($Q$The Overthrow$Q$, 3, $Q$No signs. The walls are bare. Every faction's insignia has been torn down, painted over, torn down again. The corridors lead everywhere and nowhere. Authority is a rumor. The building is listening for whoever speaks next.$Q$, $Q$Keine Schilder. Die Wände sind kahl. Die Abzeichen jeder Fraktion wurden heruntergerissen, übermalt, erneut heruntergerissen. Die Korridore führen überallhin und nirgendwohin. Autorität ist ein Gerücht. Das Gebäude hört zu, wer als Nächstes spricht.$Q$) ON CONFLICT (archetype, tier) DO UPDATE SET text_en = EXCLUDED.text_en, text_de = EXCLUDED.text_de;
